blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>8 podstawowych części mowy</strong> w języku angielskim: rzeczownik, czasownik, przymiotnik, przysłówek, zaimek, przyimek, spójnik i wykrzyknik.",
    "rules": [
        {
            "label": "Wyrazy znaczeniowe",
            "color": "emerald",
            "text": "<strong>rzeczowniki, czasowniki, przymiotniki i przysłówki</strong> niosą główne znaczenie:",
            "example": "The happy cat runs quickly."
        },
        {
            "label": "Wyrazy funkcyjne",
            "color": "blue",
            "text": "<strong>zaimki, przyimki i spójniki</strong> pomagają łączyć elementy zdania:",
            "example": "She is at home and I am here."
        },
        {
            "label": "Wykrzykniki",
            "color": "amber",
            "text": "<strong>wykrzykniki</strong> — wyrażają emocje lub reakcję:",
            "example": "Wow! Oh! Oops!"
        }
    ]
}

{
    "title": "1. Przegląd 8 części mowy",
    "intro": "W angielskim najczęściej wyróżnia się osiem podstawowych części mowy:",
    "items": [
        {
            "label": "Rzeczownik",
            "title": "Rzeczownik",
            "subtitle": "Nazwy osób, rzeczy, miejsc i pojęć: cat, John, city, love"
        },
        {
            "label": "Czasownik",
            "title": "Czasownik",
            "subtitle": "Czynności albo stany: run, eat, be, have"
        },
        {
            "label": "Przymiotnik",
            "title": "Przymiotnik",
            "subtitle": "Opisuje rzeczownik: big, red, beautiful, smart"
        },
        {
            "label": "Przysłówek",
            "title": "Przysłówek",
            "subtitle": "Opisuje czasownik, przymiotnik albo inny przysłówek: quickly, very, often"
        },
        {
            "label": "Zaimek",
            "title": "Zaimek",
            "subtitle": "Zastępuje rzeczownik: I, you, he, she, it, they"
        },
        {
            "label": "Przyimek",
            "title": "Przyimek",
            "subtitle": "Pokazuje relacje: in, on, at, under, between"
        },
        {
            "label": "Spójnik",
            "title": "Spójnik",
            "subtitle": "Łączy wyrazy i zdania: and, but, or, because"
        },
        {
            "label": "Wykrzyknik",
            "title": "Wykrzyknik",
            "subtitle": "Wyraża emocje: Oh!, Wow!, Oops!, Hey!"
        }
    ]
}

{
    "title": "2. Rzeczowniki",
    "sections": [
        {
            "label": "Co to jest rzeczownik",
            "color": "emerald",
            "description": "<strong>Rzeczownik</strong> to słowo nazywające osobę, miejsce, rzecz albo pojęcie.",
            "examples": [
                {
                    "en": "The cat is sleeping.",
                    "ua": "Kot śpi."
                },
                {
                    "en": "Mary lives in London.",
                    "ua": "Mary mieszka w Londynie."
                },
                {
                    "en": "Love is important.",
                    "ua": "Miłość jest ważna."
                }
            ]
        },
        {
            "label": "Typy rzeczowników",
            "color": "sky",
            "description": "Najczęściej rozróżniamy <strong>rzeczowniki pospolite</strong> i <strong>nazwy własne</strong>.",
            "examples": [
                {
                    "en": "common: dog, city, book",
                    "ua": "pospolite: pies, miasto, książka"
                },
                {
                    "en": "proper: Tom, Paris, Monday",
                    "ua": "własne: Tom, Paryż, Monday"
                }
            ],
            "note": "Nazwy własne zapisujemy wielką literą."
        }
    ]
}

{
    "title": "3. Verbs — czasowniki",
    "sections": [
        {
            "label": "Co to jest czasownik",
            "color": "emerald",
            "description": "<strong>Czasownik</strong> wyraża czynność albo stan.",
            "examples": [
                {
                    "en": "She runs every morning.",
                    "ua": "Ona biega każdego ranka."
                },
                {
                    "en": "He is a teacher.",
                    "ua": "On jest nauczycielem."
                },
                {
                    "en": "They have two children.",
                    "ua": "Mają dwoje dzieci."
                }
            ]
        },
        {
            "label": "Typy czasowników",
            "color": "sky",
            "description": "Często wyróżnia się <strong>action verbs</strong>, <strong>linking verbs</strong> i <strong>auxiliary verbs</strong>.",
            "examples": [
                {
                    "en": "action: run, eat, write, play",
                    "ua": "czynność: run, eat, write, play"
                },
                {
                    "en": "linking: be, seem, become",
                    "ua": "łączące: be, seem, become"
                },
                {
                    "en": "auxiliary: do, have, will, can",
                    "ua": "pomocnicze: do, have, will, can"
                }
            ]
        }
    ]
}

{
    "title": "4. Adjectives — przymiotniki",
    "sections": [
        {
            "label": "Co to jest przymiotnik",
            "color": "emerald",
            "description": "<strong>Adjective</strong> opisuje rzeczownik albo dodaje o nim informację.",
            "examples": [
                {
                    "en": "a big house",
                    "ua": "duży dom"
                },
                {
                    "en": "a beautiful flower",
                    "ua": "piękny kwiat"
                },
                {
                    "en": "The coffee is hot.",
                    "ua": "Kawa jest gorąca."
                }
            ]
        },
        {
            "label": "Pozycja przymiotnika",
            "color": "sky",
            "description": "Przymiotnik stoi zwykle <strong>przed rzeczownikiem</strong> albo <strong>po czasowniku łączącym</strong>, np. po <em>be</em>.",
            "examples": [
                {
                    "en": "a tall man",
                    "ua": "wysoki mężczyzna"
                },
                {
                    "en": "The man is tall.",
                    "ua": "Ten mężczyzna jest wysoki."
                }
            ],
            "note": "W angielskim przymiotnik nie zmienia formy przez rodzaj ani liczbę."
        }
    ]
}

{
    "title": "5. Adverbs — przysłówki",
    "sections": [
        {
            "label": "Co to jest przysłówek",
            "color": "emerald",
            "description": "<strong>Przysłówek</strong> opisuje czasownik, przymiotnik albo inny przysłówek.",
            "examples": [
                {
                    "en": "She runs quickly.",
                    "ua": "Ona biega szybko."
                },
                {
                    "en": "He is very tall.",
                    "ua": "On jest bardzo wysoki."
                },
                {
                    "en": "She speaks too quietly.",
                    "ua": "Ona mówi zbyt cicho."
                }
            ]
        },
        {
            "label": "Jak tworzymy przysłówki",
            "color": "sky",
            "description": "Wiele przysłówków powstaje przez dodanie końcówki <strong>-ly</strong> do przymiotnika.",
            "examples": [
                {
                    "en": "quick → quickly",
                    "ua": "quick → quickly"
                },
                {
                    "en": "careful → carefully",
                    "ua": "careful → carefully"
                },
                {
                    "en": "happy → happily",
                    "ua": "happy → happily"
                }
            ],
            "note": "Pamiętaj o wyjątkach, np. <strong>good → well</strong> i <strong>fast → fast</strong>."
        }
    ]
}

{
    "title": "6. Zaimki",
    "sections": [
        {
            "label": "Co to jest zaimek",
            "color": "emerald",
            "description": "<strong>Zaimek</strong> zastępuje rzeczownik, żeby uniknąć powtórzeń.",
            "examples": [
                {
                    "en": "Mary is a doctor. She works at a hospital.",
                    "ua": "Mary jest lekarką. Ona pracuje w szpitalu."
                },
                {
                    "en": "The book is interesting. It is about history.",
                    "ua": "Ta książka jest ciekawa. Ona jest o historii."
                }
            ]
        },
        {
            "label": "Typy zaimków",
            "color": "sky",
            "description": "Do najważniejszych należą zaimki <strong>osobowe</strong>, <strong>dzierżawcze</strong> i <strong>wskazujące</strong>.",
            "examples": [
                {
                    "en": "personal: I, you, he, she, it, we, they",
                    "ua": "osobowe: I, you, he, she, it, we, they"
                },
                {
                    "en": "possessive: my, your, his, her, our, their",
                    "ua": "dzierżawcze: my, your, his, her, our, their"
                },
                {
                    "en": "demonstrative: this, that, these, those",
                    "ua": "wskazujące: this, that, these, those"
                }
            ]
        }
    ]
}

{
    "title": "7. Prepositions — przyimki",
    "sections": [
        {
            "label": "Co to jest przyimek",
            "color": "emerald",
            "description": "<strong>Preposition</strong> pokazuje relację między wyrazami, na przykład miejsce, czas albo kierunek.",
            "examples": [
                {
                    "en": "The book is on the table.",
                    "ua": "Książka jest na stole."
                },
                {
                    "en": "I wake up at 7 a.m.",
                    "ua": "Budzę się o siódmej rano."
                },
                {
                    "en": "She walked to the park.",
                    "ua": "Poszła do parku."
                }
            ]
        },
        {
            "label": "Najczęstsze przyimki",
            "color": "sky",
            "description": "Najczęściej uczymy się przyimków miejsca, czasu i ruchu.",
            "examples": [
                {
                    "en": "place: in, on, at, under, behind, between",
                    "ua": "miejsce: in, on, at, under, behind, between"
                },
                {
                    "en": "time: at, on, in, before, after",
                    "ua": "czas: at, on, in, before, after"
                },
                {
                    "en": "movement: to, from, into, out of",
                    "ua": "ruch: to, from, into, out of"
                }
            ]
        }
    ]
}

{
    "title": "8. Conjunctions — spójniki",
    "sections": [
        {
            "label": "Co to jest spójnik",
            "color": "emerald",
            "description": "<strong>Conjunction</strong> łączy wyrazy, wyrażenia albo całe zdania.",
            "examples": [
                {
                    "en": "I like tea and coffee.",
                    "ua": "Lubię herbatę i kawę."
                },
                {
                    "en": "She is smart but lazy.",
                    "ua": "Jest mądra, ale leniwa."
                },
                {
                    "en": "I stayed home because it was raining.",
                    "ua": "Zostałem w domu, bo padał deszcz."
                }
            ]
        },
        {
            "label": "Typy spójników",
            "color": "sky",
            "description": "W praktyce spotkasz między innymi <strong>coordinating conjunctions</strong> i <strong>subordinating conjunctions</strong>.",
            "examples": [
                {
                    "en": "coordinating: and, but, or, so, yet",
                    "ua": "współrzędne: and, but, or, so, yet"
                },
                {
                    "en": "subordinating: because, if, when, although",
                    "ua": "podrzędne: because, if, when, although"
                }
            ],
            "note": "Skrót <strong>FANBOYS</strong> pomaga zapamiętać część spójników współrzędnych."
        }
    ]
}

{
    "title": "9. Interjections — wykrzykniki",
    "sections": [
        {
            "label": "Co to jest wykrzyknik",
            "color": "emerald",
            "description": "<strong>Interjection</strong> wyraża emocję albo natychmiastową reakcję.",
            "examples": [
                {
                    "en": "Wow! That is amazing!",
                    "ua": "Wow! To niesamowite!"
                },
                {
                    "en": "Oops! I made a mistake.",
                    "ua": "Oops! Popełniłem błąd."
                },
                {
                    "en": "Hurray! We won!",
                    "ua": "Hurra! Wygraliśmy!"
                }
            ]
        },
        {
            "label": "Popularne wykrzykniki",
            "color": "sky",
            "description": "Wykrzykniki często stoją samodzielnie i w mowie dodają wypowiedzi emocji.",
            "examples": [
                {
                    "en": "Oh! Ah! Wow! Hey! Ouch!",
                    "ua": "Oh! Ah! Wow! Hey! Ouch!"
                },
                {
                    "en": "Well, I think so.",
                    "ua": "Well, I think so."
                }
            ],
            "note": "W bardzo formalnym stylu używa się ich oszczędniej."
        }
    ]
}

{
    "title": "10. Tabela podsumowująca części mowy",
    "intro": "Oto osiem podstawowych części mowy i ich funkcje:",
    "rows": [
        {
            "en": "Noun",
            "ua": "rzeczownik",
            "note": "nazywa: cat, city, love"
        },
        {
            "en": "Verb",
            "ua": "czasownik",
            "note": "czynność lub stan: run, is, have"
        },
        {
            "en": "Adjective",
            "ua": "przymiotnik",
            "note": "opisuje rzeczownik: big, red"
        },
        {
            "en": "Adverb",
            "ua": "przysłówek",
            "note": "opisuje czasownik lub przymiotnik: quickly, very"
        },
        {
            "en": "Pronoun",
            "ua": "zaimek",
            "note": "zastępuje rzeczownik: I, she, they"
        },
        {
            "en": "Preposition",
            "ua": "przyimek",
            "note": "pokazuje relację: in, on, at"
        },
        {
            "en": "Conjunction",
            "ua": "spójnik",
            "note": "łączy: and, but, because"
        },
        {
            "en": "Interjection",
            "ua": "wykrzyknik",
            "note": "wyraża emocje: Wow! Oh! Oops!"
        }
    ],
    "warning": "📌 To samo słowo może należeć do różnych części mowy w zależności od kontekstu, np. <strong>run</strong> jako czasownik i jako rzeczownik."
}

{
    "title": "11. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Mylenie przymiotnika z przysłówkiem.",
            "wrong": "She speaks English good.",
            "right": "✅ <span class=\"font-mono\">She speaks English well.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie przymiotnika zamiast przysłówka.",
            "wrong": "He runs quick.",
            "right": "✅ <span class=\"font-mono\">He runs quickly.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Niepoprawny zaimek w funkcji podmiotu.",
            "wrong": "Me and Tom went to school.",
            "right": "✅ <span class=\"font-mono\">Tom and I went to school.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Brak przedimka przy rzeczowniku policzalnym w liczbie pojedynczej.",
            "wrong": "I have cat.",
            "right": "✅ <span class=\"font-mono\">I have a cat.</span>"
        }
    ]
}

{
    "title": "13. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Rozpoznaj część mowy",
    "select_intro": "Wskaż, jaką częścią mowy jest wyróżnione słowo.",
    "selects": [
        {
            "label": "The CAT is sleeping. (noun / verb / adjective)",
            "prompt": "Jaka to część mowy?"
        },
        {
            "label": "She QUICKLY finished her work. (adjective / adverb / noun)",
            "prompt": "Jaka to część mowy?"
        },
        {
            "label": "They went TO the park. (conjunction / preposition / adverb)",
            "prompt": "Jaka to część mowy?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Ćwiczenie 2. Wybierz poprawną formę",
    "input_intro": "Wpisz właściwe słowo.",
    "inputs": [
        {
            "before": "She sings (beautiful / beautifully)",
            "after": "→"
        },
        {
            "before": "He is a (good / well) student",
            "after": "→"
        },
        {
            "before": "They work (hard / hardly) every day",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Rozłóż zdanie na części mowy",
    "rephrase_intro": "Nazwij funkcję poszczególnych wyrazów w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "The happy dog runs quickly.",
            "example_target": "The (przedimek), happy (przymiotnik), dog (rzeczownik), runs (czasownik), quickly (przysłówek)."
        },
        {
            "original": "1. She and I went to school yesterday.",
            "placeholder": "Rozpoznaj części mowy"
        },
        {
            "original": "2. Wow! The big cat is sleeping on the soft bed.",
            "placeholder": "Rozpoznaj części mowy"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Części mowy",
            "current": true
        },
        {
            "label": "Podstawowy szyk",
            "current": false
        },
        {
            "label": "Pytania i przeczenia",
            "current": false
        }
    ]
}
